import React, { useEffect, useState } from 'react';
import { Line } from 'react-chartjs-2';
import { Clock } from 'lucide-react';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend
} from 'chart.js';
import api from '../services/api';
import { CarbonTrend, Prediction, DetectionResult } from '../types';

ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend
);

interface DashboardProps {
  detections: DetectionResult[];
}

export const Dashboard: React.FC<DashboardProps> = ({ detections }) => {
  const [metrics, setMetrics] = useState<any>(null);
  const [trends, setTrends] = useState<CarbonTrend[]>([]);
  const [predictions, setPredictions] = useState<Prediction[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchData();
  }, []);

  const isNetworkError = (err: any): boolean => {
    if (!err) return true;
    return (
      !err.response ||
      err.code === 'ECONNABORTED' ||
      err.code === 'ENOTFOUND' ||
      err.code === 'ECONNREFUSED' ||
      err.isNetworkError === true ||
      (err.message && (
        err.message.includes('Network') || 
        err.message.includes('Failed to fetch') ||
        err.message.includes('timeout') ||
        err.message.includes('ERR_NETWORK')
      ))
    );
  };

  const fetchData = async () => {
    try {
      const [metricsRes, trendsRes, predictionsRes] = await Promise.all([
        api.get('/analytics/dashboard', { timeout: 8000 }),
        api.get('/detection/emissions-trend?days=30', { timeout: 8000 }),
        api.get('/prediction/future-emissions?days=30', { timeout: 8000 })
      ]);

      setMetrics(metricsRes.data);
      setTrends(trendsRes.data);
      setPredictions(predictionsRes.data);
    } catch (error: any) {
      // Use mock data if backend not running
      if (isNetworkError(error)) {
        const mockTrends: CarbonTrend[] = [
          { date: new Date(Date.now() - 5*24*60*60*1000).toISOString(), total_emissions: 8.5, count: 3, average: 2.8 },
          { date: new Date(Date.now() - 4*24*60*60*1000).toISOString(), total_emissions: 10.2, count: 4, average: 2.5 },
          { date: new Date(Date.now() - 3*24*60*60*1000).toISOString(), total_emissions: 7.9, count: 2, average: 3.9 },
          { date: new Date(Date.now() - 2*24*60*60*1000).toISOString(), total_emissions: 12.1, count: 5, average: 2.4 },
          { date: new Date(Date.now() - 1*24*60*60*1000).toISOString(), total_emissions: 9.3, count: 3, average: 3.1 },
          { date: new Date().toISOString(), total_emissions: 11.5, count: 4, average: 2.8 }
        ];
        
        const mockPredictions: Prediction[] = [];
        for (let i = 1; i <= 30; i++) {
          const date = new Date(Date.now() + i*24*60*60*1000);
          mockPredictions.push({
            date: date.toISOString(),
            predicted_emissions: 10 + Math.random() * 5,
            trend: i % 3 === 0 ? 'Increasing' : i % 2 === 0 ? 'Decreasing' : 'Stable',
            confidence: 0.75 + Math.random() * 0.2
          });
        }
        
        setMetrics({
          total_detections: 21,
          total_emissions: 58.9,
          average_emissions: 2.8,
          top_detected_object: 'car',
          top_object_emissions: 15.0
        });
        setTrends(mockTrends);
        setPredictions(mockPredictions);
      } else {
        console.error('Error fetching dashboard data:', error);
      }
    } finally {
      setLoading(false);
    }
  };

  if (loading) return <div>Loading dashboard...</div>;

  const trendChartData = {
    labels: trends.map(t => new Date(t.date).toLocaleDateString()),
    datasets: [
      {
        label: 'Daily Emissions (kg CO2e)',
        data: trends.map(t => t.total_emissions),
        borderColor: 'rgb(75, 192, 192)',
        backgroundColor: 'rgba(75, 192, 192, 0.1)',
        tension: 0.4
      }
    ]
  };

  const predictionChartData = {
    labels: predictions.map(p => new Date(p.date).toLocaleDateString()),
    datasets: [
      {
        label: 'Predicted Emissions (kg CO2e)',
        data: predictions.map(p => p.predicted_emissions),
        borderColor: 'rgb(255, 159, 64)',
        backgroundColor: 'rgba(255, 159, 64, 0.1)',
        tension: 0.4
      }
    ]
  };

  return (
    <div className="w-full bg-gradient-to-br from-blue-50 to-green-50 p-8 rounded-lg">
      <h1 className="text-4xl font-bold text-gray-800 mb-8">Carbon Footprint Dashboard</h1>

      {/* Metrics Cards */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-8">
        <div className="bg-white p-6 rounded-lg shadow-md">
          <p className="text-sm text-gray-600">Total Emissions</p>
          <p className="text-3xl font-bold text-green-600">{metrics?.total_emissions || 0}</p>
          <p className="text-xs text-gray-500">kg CO2e</p>
        </div>
        <div className="bg-white p-6 rounded-lg shadow-md">
          <p className="text-sm text-gray-600">Total Detections</p>
          <p className="text-3xl font-bold text-blue-600">{metrics?.total_detections || 0}</p>
        </div>
        <div className="bg-white p-6 rounded-lg shadow-md">
          <p className="text-sm text-gray-600">Average per Detection</p>
          <p className="text-3xl font-bold text-orange-600">{metrics?.average_emissions || 0}</p>
          <p className="text-xs text-gray-500">kg CO2e</p>
        </div>
        <div className="bg-white p-6 rounded-lg shadow-md">
          <p className="text-sm text-gray-600">Top Detected</p>
          <p className="text-2xl font-bold text-purple-600">{metrics?.top_detected_object || 'N/A'}</p>
        </div>
      </div>

      {/* Charts */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-6 rounded-lg shadow-lg">
          <h2 className="text-xl font-bold text-gray-800 mb-4">Historical Trends (Past 30 Days)</h2>
          <Line data={trendChartData} options={{ responsive: true }} />
        </div>

        <div className="bg-white p-6 rounded-lg shadow-lg">
          <h2 className="text-xl font-bold text-gray-800 mb-4">Future Predictions (Next 30 Days)</h2>
          <Line data={predictionChartData} options={{ responsive: true }} />
        </div>
      </div>

      {/* Recent Searches Section */}
      {detections.length > 0 && (
        <div className="mt-8 bg-white p-6 rounded-lg shadow-lg">
          <div className="flex items-center gap-3 mb-6">
            <Clock className="w-6 h-6 text-blue-600" />
            <h2 className="text-2xl font-bold text-gray-800">Recent Image Analyses</h2>
            <span className="ml-auto bg-blue-100 text-blue-800 px-3 py-1 rounded-full text-sm font-semibold">
              {detections.length} image{detections.length !== 1 ? 's' : ''}
            </span>
          </div>

          <div className="space-y-3 max-h-96 overflow-y-auto">
            {[...detections].reverse().map((detection, idx) => {
              const objectNames = detection.objects.map(obj => obj.name).join(', ');
              const detectionDate = new Date(detection.timestamp);
              const timeAgo = Math.floor((Date.now() - detectionDate.getTime()) / 1000);
              let timeStr = '';
              
              if (timeAgo < 60) timeStr = 'just now';
              else if (timeAgo < 3600) timeStr = `${Math.floor(timeAgo / 60)}m ago`;
              else if (timeAgo < 86400) timeStr = `${Math.floor(timeAgo / 3600)}h ago`;
              else timeStr = `${Math.floor(timeAgo / 86400)}d ago`;

              return (
                <div key={idx} className="flex items-center justify-between p-4 bg-gradient-to-r from-blue-50 to-green-50 rounded-lg border-l-4 border-blue-500 hover:shadow-md transition">
                  <div className="flex-1">
                    <div className="flex items-center gap-2 mb-1">
                      <p className="font-semibold text-gray-800">📸 {objectNames}</p>
                      <span className="text-xs text-gray-500 bg-white px-2 py-1 rounded">
                        {timeStr}
                      </span>
                    </div>
                    <div className="flex gap-4 text-sm text-gray-600">
                      <span>📊 {detection.total_emissions.toFixed(2)} kg CO₂e</span>
                      <span>🎯 {detection.objects.length} object{detection.objects.length !== 1 ? 's' : ''}</span>
                      <span>✓ {(detection.objects[0]?.confidence * 100).toFixed(0)}% confidence avg</span>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="text-xs text-gray-500">{detectionDate.toLocaleDateString()}</p>
                    <p className="text-xs text-gray-500">{detectionDate.toLocaleTimeString()}</p>
                  </div>
                </div>
              );
            })}
          </div>

          {detections.length === 0 && (
            <p className="text-center text-gray-500 py-8">No recent analyses yet. Upload an image to get started!</p>
          )}
        </div>
      )}
    </div>
  );
};
